// Sanitize header values to prevent injection attacks
function sanitizeHeaderValue(value) {
  if (typeof value === 'string') {
    // Remove or escape problematic characters
    return value
      .replace(/\r/g, '')
      .replace(/\n/g, '')
      .replace(/\0/g, '')
      .trim();
  }
  return String(value);
}

